,p_static_id=>'appointments'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT p.full_name || '' - '' ||',
'       TO_CHAR(a.appointment_date, ''DD-MON-YYYY'') AS display_value,',
'       a.appointment_id AS return_value',
